beforeHooks.code:
this.timeout(60000);
fkHeaders = await CommonAPI.tokenCreation('Flipkart');
// Pre-generate PAN + mobile for negative tests (reused in all assert400 calls).
// No app is created here — each positive test creates its own, and negative tests
// build bad-payload requests directly using sharedNegPan/Mobile.
const { panNumber } = await suppressLogging(() => CommonAPI.createPan());
const { mobile }    = await suppressLogging(() => CommonAPI.updateCibil(panNumber));
sharedNegPan = panNumber; sharedNegMobile = mobile;
console.log(`[OS-2253 SETUP] ready — sharedNegPan: ${sharedNegPan}`);

tests.code:
// No income — using annual_turnover as the income gate (like P-02).
// income + business fields together causes offer Error in QA bureau.
const SLAB = 'Rs.0 to 40 lakhs';
const { appId, res, txnId } = await createSenpAppAndOffer(this,
    {
        'employment.emp_type':           'SELFEMP',
        'employment.annual_turnover':    SLAB,
        'employment.nature_of_business': 'Manufacturer',
        'employment.business_type':      'Proprietorship',
    },
    { removeIncome: true }
);
expect(res.status, 'App Create HTTP').to.equal(200);
expect(appId, 'application_id').to.be.a('string').and.not.be.empty;
await verifyDownstream(this, appId, {
    annual_turnover:    SLAB,
    nature_of_business: 'Manufacturer',
    business_type:      'Proprietorship',
});

const SLAB = 'Rs.40 lakhs to 1.5 Cr.';
const { appId, res, txnId } = await createSenpAppAndOffer(this,
    { 'employment.emp_type': 'SELFEMP', 'employment.annual_turnover': SLAB },
    { removeIncome: true }
);
expect(res.status, 'App Create HTTP').to.equal(200);
await verifyDownstream(this, appId, { annual_turnover: SLAB });

const { appId, res, txnId } = await createSenpAppAndOffer(this,
    { 'employment.emp_type': 'SELFEMP', 'employment.income': 50000 });
expect(res.status, 'App Create HTTP').to.equal(200);
await verifyDownstream(this, appId, { income: 50000 });
// (OMNI_1/PRE/HC/POST report is now produced inside verifyDownstream for every case.)

